package tournament.presentation;
import tournament.application.*; import tournament.domain.TournamentType;
public class DemoRunner { private final TournamentService tournamentService; private final MatchService matchService; private final StandingsService standingsService; private final DisputeService disputeService; private final TournamentConsoleUI ui; public DemoRunner(TournamentService ts,MatchService ms,StandingsService ss,DisputeService ds,TournamentConsoleUI ui){this.tournamentService=ts;this.matchService=ms;this.standingsService=ss;this.disputeService=ds;this.ui=ui;} public void runScriptedDemo(){ tournamentService.createTournament("organizer1","Campus Showdown",TournamentType.ROUND_ROBIN); tournamentService.openRegistration("organizer1"); tournamentService.registerTeam("captain1","Falcons","Alice"); tournamentService.registerTeam("captain2","Wolves","Bob"); tournamentService.registerTeam("captain3","Titans","Carol"); tournamentService.registerTeam("captain4","Sharks","Dave"); tournamentService.addPlayerToTeam("captain1","Falcons","F1"); tournamentService.addPlayerToTeam("captain2","Wolves","W1"); tournamentService.addPlayerToTeam("captain3","Titans","T1"); tournamentService.addPlayerToTeam("captain4","Sharks","S1"); tournamentService.closeRegistrationAndSeed("organizer1"); tournamentService.generateSchedule("organizer1"); tournamentService.startTournament("organizer1"); matchService.submitResult("ref1",1,2,1); matchService.submitResult("ref1",2,0,0); ui.showTournamentSummary(tournamentService.getCurrentTournament()); ui.showStandings(standingsService.getStandings()); disputeService.openDispute("captain1",1,"Possible score entry issue"); ui.showDisputes(disputeService.getDisputes()); ui.showAuditLog(); } }
